// gameLogic/movement.js

// Define the size of the game board
export const BOARD_SIZE = 28;

// Function to check if a move is valid for a knight-like piece
export function isValidMove(startX, startY, targetX, targetY) {
  const dx = Math.abs(targetX - startX);
  const dy = Math.abs(targetY - startY);
  return (dx === 1 && dy === 2) || (dx === 2 && dy === 1);
}

// Function to move the player piece
export function movePiece(startX, startY, targetX, targetY) {
  if (isValidMove(startX, startY, targetX, targetY)) {
    // Perform the move
    // Update player position or trigger other game events
    console.log(`Moved to (${targetX}, ${targetY})`);
    return true; // Return true if move is valid
  } else {
    console.log('Invalid move');
    return false; // Return false if move is invalid
  }
}

// gameLogic/movement.js

export function getValidKnightMoves(playerPosition) {
  const { row, col } = playerPosition;
  const validMoves = [];
  const knightMoves = [
    { dx: -2, dy: -1 },
    { dx: -2, dy: 1 },
    { dx: -1, dy: -2 },
    { dx: -1, dy: 2 },
    { dx: 1, dy: -2 },
    { dx: 1, dy: 2 },
    { dx: 2, dy: -1 },
    { dx: 2, dy: 1 },
  ];

  knightMoves.forEach(move => {
    const newRow = row + move.dx;
    const newCol = col + move.dy;
    // Check if the new position is within the board bounds
    if (newRow >= 0 && newRow < BOARD_SIZE && newCol >= 0 && newCol < BOARD_SIZE) {
      validMoves.push({ row: newRow, col: newCol });
    }
  });

  return validMoves;
}

// Function to get valid moves for a pawn
export function getValidPawnMoves(playerPosition) {
  const { row, col } = playerPosition;
  const validMoves = [];

  // Define the direction of movement for the pawn based on player's side
  const direction = (playerPosition.side === 'white') ? 1 : -1;

  // Check if moving one square forward is valid
  const newRow = row + direction;
  if (newRow >= 0 && newRow < BOARD_SIZE) {
    validMoves.push({ row: newRow, col: col });
  }

  // Check if moving two squares forward (if in starting position) is valid
  if ((playerPosition.side === 'white' && row === 1) || (playerPosition.side === 'black' && row === BOARD_SIZE - 2)) {
    const doubleRow = row + 2 * direction;
    if (doubleRow >= 0 && doubleRow < BOARD_SIZE) {
      validMoves.push({ row: doubleRow, col: col });
    }
  }

  // Implement logic for capturing diagonally
  // For example, if a pawn can capture diagonally one square ahead, add those moves to validMoves array

  return validMoves;
}

